export async function writeRunConfig(
  specPackRoot: string,
  config: ImplRunConfig
): Promise<string> {
  const configPath = join(specPackRoot, "impl-run.config.json");
  await writeTextFile(configPath, `${JSON.stringify(config, null, 2)}\n`);
