    tests: z.object({
      added: z.array(z.string().min(1)),
      modified: z.array(z.string().min(1)),
      removed: z.array(z.string().min(1)),
      totalAfterStory: z.number().int().optional(),
      deltaFromPriorBaseline: z.number().int().optional(),
    }),
    gatesRun: z.array(
